import { api, BASE } from './client'
import { getAccessToken } from '../lib/authStorage'

export interface ScratchProjectDto {
  id: string
  ownerId: string
  title: string
  description: string | null
  sb3Path: string
  thumbnailUrl: string | null
  lessonId: string | null
  courseSlug: string | null
  submittedAt: string | null
  gradedAt: string | null
  gradedBy: string | null
  grade: number | null
  feedback: string | null
  isPublic: boolean
  shareToken: string | null
  viewCount: number
  sizeBytes: number
  createdAt: string
  updatedAt: string
}

async function multipart<T>(method: string, path: string, fd: FormData): Promise<T> {
  const token = getAccessToken()
  const res = await fetch(`${BASE}${path}`, {
    method,
    credentials: 'include',
    headers: { ...(token ? { Authorization: `Bearer ${token}` } : {}) },
    body: fd,
  })
  if (!res.ok) {
    const txt = await res.text().catch(() => '')
    const err = new Error(txt || res.statusText) as Error & { status?: number }
    err.status = res.status
    throw err
  }
  return (await res.json()) as T
}

export function fetchMyScratchProjects(): Promise<ScratchProjectDto[]> {
  return api.get<ScratchProjectDto[]>('/scratch-projects/my').catch(() => [])
}

export function fetchStudentScratchProjects(studentId: string): Promise<ScratchProjectDto[]> {
  return api.get<ScratchProjectDto[]>(`/scratch-projects/student/${studentId}`).catch(() => [])
}

export interface GetScratchProjectResult {
  project: ScratchProjectDto
  canEdit: boolean
}

export function getScratchProject(id: string): Promise<GetScratchProjectResult> {
  return api.get<GetScratchProjectResult>(`/scratch-projects/${id}`)
}

export function createScratchProject(fd: FormData): Promise<ScratchProjectDto> {
  return multipart<ScratchProjectDto>('POST', '/scratch-projects', fd)
}

export function updateScratchProject(id: string, fd: FormData): Promise<ScratchProjectDto> {
  return multipart<ScratchProjectDto>('PATCH', `/scratch-projects/${id}`, fd)
}

export function submitScratchProject(id: string): Promise<ScratchProjectDto> {
  return api.patch<ScratchProjectDto>(`/scratch-projects/${id}/submit`, {})
}

export function gradeScratchProject(id: string, grade: number, feedback: string): Promise<ScratchProjectDto> {
  return api.patch<ScratchProjectDto>(`/scratch-projects/${id}/grade`, { grade, feedback })
}

export function toggleSharePublic(id: string, isPublic: boolean): Promise<{ shareToken: string | null }> {
  return api.patch<{ shareToken: string | null }>(`/scratch-projects/${id}/share`, { isPublic })
}

export function deleteScratchProject(id: string): Promise<void> {
  return api.delete(`/scratch-projects/${id}`)
}

export function fetchPublicScratch(token: string): Promise<ScratchProjectDto> {
  return fetch(`${BASE}/scratch-projects/public/${encodeURIComponent(token)}`).then((r) => {
    if (!r.ok) throw new Error('not found')
    return r.json() as Promise<ScratchProjectDto>
  })
}
